# Category: insecure_log_storage

import os
import datetime

# Define the log storage location
log_dir = '/var/log'

# Define the log rotation settings
log_rotation_interval = 14 # days
log_rotation_count = 7 # number of logs to keep

# Set file permissions for log files
os.chmod(log_dir, 0o755)

# Implement log rotation
def rotate_logs():
    # Get the current date and time
    now = datetime.datetime.now()

    # Create a new log file for today's date
    log_file = f"{log_dir}/app_{now:%Y-%m-%d}.log"
    open(log_file, 'a').close()

    # Delete old logs based on the rotation settings
    for i in range(log_rotation_count):
        oldest_log = now - datetime.timedelta(days=i*log_rotation_interval)
        oldest_log_file = f"{log_dir}/app_{oldest_log:%Y-%m-%d}.log"
        if os.path.exists(oldest_log_file):
            os.remove(oldest_log_file)

# Initialize the log rotation
rotate_logs()